+import React from "react";
+
+type Props = {
+  srcDoc: string;
+  title?: string;
+  width?: number | string;
+  height?: number | string;
+  /**
+   * Whether the embed truly needs allow-same-origin. Default false.
+   * This should only be enabled by callers that require same-origin access
+   * to the embedded document (e.g. for postMessage/read access to cookies).
+   */
+  allowSameOrigin?: boolean;
+};
+
+// Escape HTML characters to avoid injection when constructing a srcdoc.
+function escapeHtml(raw: string): string {
+  return raw
+    .replace(/&/g, "&amp;")
+    .replace(/</g, "&lt;")
+    .replace(/>/g, "&gt;")
+    .replace(/"/g, "&quot;")
+    .replace(/'/g, "&#39;");
+}
+
+// Build a safe srcdoc by placing the user content into a safe wrapper.
+// We intentionally do NOT render the raw HTML verbatim. Instead we treat
+// the incoming string as opaque data and escape it so that it cannot
+// break out into active HTML/script contexts.
+function buildSafeSrcDoc(content: string): string {
+  // Minimal HTML document; ensure a charset and safe viewport.
+  // The user-supplied content is escaped to avoid HTML/attribute injection.
+  return `<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><div data-excalidraw-embed>${escapeHtml(
+    content,
+  )}</div></body></html>`;
+}
+
+export default function Embed({
+  srcDoc,
+  title = "Excalidraw embed",
+  width = "100%",
+  height = 400,
+  allowSameOrigin = false,
+}: Props) {
+  // Build a sandbox string using the principle of least privilege.
+  // allow-same-origin is only included when explicitly requested.
+  const sandboxFlags = ["allow-forms", "allow-scripts"];
+  if (allowSameOrigin) {
+    sandboxFlags.push("allow-same-origin");
+  }
+
+  return (
+    <iframe
+      title={title}
+      // Use a sanitized srcdoc that escapes injected HTML instead of rendering
+      // untrusted content verbatim.
+      srcDoc={buildSafeSrcDoc(srcDoc)}
+      style={{ width, height, border: 0 }}
+      sandbox={sandboxFlags.join(" ")}
+    />
+  );
+}
