+import React from 'react';
+
+type Props = {
+    welcomeMessage?: string;
+};
+
+/**
+ * Sanitize a fragment of HTML for safe insertion into the login page.
+ * This is a minimal, DOM-based sanitizer:
+ * - removes <script> elements
+ * - strips attributes that start with "on" (event handlers)
+ * - strips style attributes
+ * - removes href/src attributes that use "javascript:" or other executable schemes
+ *
+ * Using a DOMParser keeps the sanitizer free of external deps and is sufficient
+ * for the welcome message use-case where administrators provide small HTML snippets.
+ */
+function sanitizeWelcomeMessage(html: string): string {
+    if (!html) {
+        return '';
+    }
+
+    // Parse into a document so we can examine nodes safely
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(html, 'text/html');
+
+    // Remove any <script> elements
+    const scripts = Array.from(doc.getElementsByTagName('script'));
+    for (const s of scripts) {
+        s.parentNode?.removeChild(s);
+    }
+
+    // Walk elements and clean attributes
+    const walker = doc.createTreeWalker(doc.body, NodeFilter.SHOW_ELEMENT, null);
+    let node = walker.currentNode as Element | null;
+    while (node) {
+        // Collect attributes to remove
+        const attrsToRemove: string[] = [];
+        for (let i = 0; i < node.attributes.length; i++) {
+            const attr = node.attributes.item(i);
+            if (!attr) {
+                continue;
+            }
+            const name = attr.name.toLowerCase();
+            const value = attr.value.trim().toLowerCase();
+
+            // Remove event handler attributes like onclick, onerror, etc.
+            if (name.startsWith('on')) {
+                attrsToRemove.push(attr.name);
+                continue;
+            }
+
+            // Strip style attributes entirely to avoid CSS-based attacks
+            if (name === 'style') {
+                attrsToRemove.push(attr.name);
+                continue;
+            }
+
+            // Prevent javascript: and data: URIs in href/src attributes
+            if ((name === 'href' || name === 'src') && (value.startsWith('javascript:') || value.startsWith('data:'))) {
+                attrsToRemove.push(attr.name);
+                continue;
+            }
+        }
+
+        for (const a of attrsToRemove) {
+            node.removeAttribute(a);
+        }
+
+        node = walker.nextNode() as Element | null;
+    }
+
+    // Return sanitized inner HTML
+    return doc.body.innerHTML;
+}
+
+const WelcomeMessage: React.FC<Props> = ({ welcomeMessage }) => {
+    if (!welcomeMessage) {
+        return null;
+    }
+
+    const sanitized = sanitizeWelcomeMessage(welcomeMessage);
+
+    return (
+        <div
+            className="welcome-message"
+            // Note: inner HTML is safe after sanitization above.
+            dangerouslySetInnerHTML={{ __html: sanitized }}
+        />
+    );
+};
+
+export default WelcomeMessage;
