+/// Verify that `qe_identity` (raw bytes) is signed by the private key corresponding to the
+/// first certificate in `issuer_chain_pem`. The signature is provided base64-encoded in
+/// `signature_b64`. Additionally ensure that the issuer chain is non-empty and contains
+/// at least one certificate whose subject mentions "Intel" to provide a minimal sanity
+/// check that the chain points to Intel-issued certificates.
+fn verify_qe_identity_signature(
+    qe_identity: &[u8],
+    signature_b64: &str,
+    issuer_chain_pem: &str,
+) -> Result<()> {
+    // Decode signature (PCCS supplies base64)
+    let signature = general_purpose::STANDARD
+        .decode(signature_b64)
+        .map_err(|e| anyhow!("failed to base64-decode QE Identity signature: {}", e))?;
+
+    // Parse PEM chain into X509 certificates. Expect at least one cert (leaf).
+    let certs = X509::stack_from_pem(issuer_chain_pem.as_bytes())
+        .map_err(|e| anyhow!("failed to parse issuer chain PEM: {}", e))?;
+    if certs.is_empty() {
+        return Err(anyhow!("empty issuer chain in QE Identity collateral"));
+    }
+
+    // Minimal sanity: require at least one cert subject to contain "Intel".
+    let found_intel = certs.iter().any(|c| {
