+    // Use the leaf certificate's public key to verify the signature over qe_identity.
+    let leaf = &certs[0];
+    let pubkey = leaf
+        .public_key()
+        .map_err(|e| anyhow!("failed to extract public key from leaf cert: {}", e))?;
