+// NOTE: New secure simple file server.
+// This file replaces ad-hoc shell execution with direct file streaming.
+import { createReadStream } from 'fs';
+import { resolve as resolvePath, normalize as normalizePath } from 'path';
+
+// Base directory to serve files from. Defaults to current working directory.
+const BASE_DIR = process.env.FILE_BASE_DIR
+  ? resolvePath(process.env.FILE_BASE_DIR)
+  : resolvePath(process.cwd());
+
+// Allowed filename characters (prevents injection characters like ;|&$` etc.)
+// This pattern permits alphanumerics, dot, underscore, hyphen and slash.
+const SAFE_FILENAME_RE = /^[A-Za-z0-9._\-\/]+$/;
+
+export function serveFile(req, res) {
+  const raw = (req.query && req.query.file) || (req.params && req.params.file);
+
+  if (!raw || typeof raw !== 'string') {
+    res.statusCode = 400;
+    res.end('missing file');
+    return;
+  }
+
+  if (!SAFE_FILENAME_RE.test(raw)) {
+    res.statusCode = 400;
+    res.end('invalid file name');
+    return;
+  }
+
+  // Resolve and normalize to prevent directory traversal.
+  const normalized = normalizePath(raw);
+  const fullPath = resolvePath(BASE_DIR, normalized);
+
+  // Ensure the resolved path is inside the allowed base directory.
+  if (!fullPath.startsWith(BASE_DIR + '/') && fullPath !== BASE_DIR) {
+    res.statusCode = 403;
+    res.end('forbidden');
+    return;
+  }
+
+  const stream = createReadStream(fullPath);
+  stream.on('error', (err) => {
+    // Don't leak internal errors to clients.
+    res.statusCode = err && err.code === 'ENOENT' ? 404 : 500;
+    res.end(err && err.code === 'ENOENT' ? 'not found' : 'error reading file');
+  });
+  // Pipe file contents directly to response (no shell invocation).
+  stream.pipe(res);
+}
