+/**
+ * Small utility to safely consume request body without accidentally
+ * reading bytes that belong to a subsequent pipelined HTTP request.
+ *
+ * The root cause of CVE-2024-34350 was that code which consumed the
+ * request body could read more bytes than the Content-Length (or other
+ * expected length) and thus consume bytes from the next pipelined
+ * request on the same socket. Those extra bytes would be lost to the
+ * Node HTTP parser and could cause the server and application to have
+ * an inconsistent view of requests, enabling response queue poisoning.
+ *
+ * This module provides a single exported helper that reads up to the
+ * expected length (if known) and, if a chunk read from the incoming
+ * stream contains extra bytes, puts the extra bytes back onto the
+ * socket using socket.unshift(...) so they can be parsed as the next
+ * request by the Node HTTP parser.
+ */
+
+import { IncomingMessage, Socket } from 'http';
+
+/**
+ * Read the request body up to an expected length. If expectedLength is
+ * not provided, and the Content-Length header is present, that value
+ * will be used. If no length is known, the whole stream will be read.
+ *
+ * Any extra bytes read beyond the expected length are pushed back onto
+ * the underlying socket so they aren't consumed as part of this
+ * request. This prevents desynchronization between Next.js' body
+ * consumption and Node's HTTP parser.
+ *
+ * Returns a Buffer containing at most expectedLength bytes (or full
+ * body if no expected length).
+ */
+export async function consumeRequestBody(
+  req: IncomingMessage,
+  expectedLength?: number
+): Promise<Buffer> {
+  const contentLengthHeader = req.headers['content-length'];
+  const contentLength =
+    expectedLength ??
+    (typeof contentLengthHeader === 'string'
+      ? parseInt(contentLengthHeader, 10)
+      : undefined);
+
+  const chunks: Buffer[] = [];
+  let received = 0;
+
+  for await (const chunk of req) {
+    const buf = Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk);
+    const remaining = contentLength !== undefined ? contentLength - received : undefined;
+
+    if (remaining === undefined || remaining >= buf.length) {
+      // We can consume the whole chunk as part of this request.
+      chunks.push(buf);
+      received += buf.length;
+      continue;
+    }
+
+    // The chunk contains more bytes than we should consume for this
+    // request. Slice the needed portion and push the remainder back
+    // onto the socket so Node's parser can treat it as the next
+    // pipelined request.
+    if (remaining > 0) {
+      chunks.push(buf.slice(0, remaining));
+      received += remaining;
+    }
+
+    const remainder = buf.slice(Math.max(0, remaining));
+
+    // Attempt to unshift the remainder back into the socket. The
+    // underlying socket is a Duplex stream and supports unshift for
+    // raw data. Guard against the unlikely case where socket or
+    // unshift isn't available.
+    const socket = req.socket as Socket | undefined;
+    if (socket && typeof (socket as any).unshift === 'function') {
+      try {
+        (socket as any).unshift(remainder);
+      } catch {
+        // If unshift fails for whatever reason, there's nothing safe we
+        // can do here. Avoid throwing because callers may expect to
+        // receive a body buffer; fall through and return what we have.
+      }
+    }
+
+    // We've taken what we needed for this request; stop reading.
+    break;
+  }
+
+  return Buffer.concat(chunks, received);
+}
